exercises.solution:
import numpy as np
from scipy.optimize import minimize

def noisy_fn(x, noise=0.1):
    return np.sum(x**2) + noise * np.random.randn()

def compare_optimizers(fn, x0, trials=10):
    results = {'cobyla': [], 'nelder-mead': []}
    for _ in range(trials):
        for method in ['COBYLA', 'Nelder-Mead']:
            res = minimize(fn, x0, method=method, options={'maxiter': 100})
            results[method.lower()].append(res.fun)
    return {m: {'mean': np.mean(v), 'std': np.std(v)} for m, v in results.items()}

results = compare_optimizers(noisy_fn, np.array([2.0, 2.0]))
for m, r in results.items():
    print(f"{m}: {r['mean']:.4f} +/- {r['std']:.4f}")

